"use strict";parserFactory.register("twkan.com",()=>new TwkanParser);class TwkanParser extends Parser{constructor(){super(),this.minimumThrottle=1e3}async getChapterUrls(t){let e=this.extractBookId(t.baseURI);if(!e){let r=t.querySelector("meta[property='og:book_id']");r&&(e=r.getAttribute("content"))}if(!e)throw new Error("Could not extract book ID from URL");let r=`https://twkan.com/ajax_novels/chapterlist/${e}.html`;return[...(await HttpClient.wrapFetch(r)).responseXML.querySelectorAll("ul li a")].filter(t=>t.href.includes("/txt/")).map(t=>util.hyperLinkToChapter(t))}findContent(t){return t.querySelector("#txtcontent0")}extractTitleImpl(t){let e=t.querySelector(".booknav2 h1 a, .booknav2 h1, h1 a");if(e)return e.textContent.trim();let r=t.querySelector("meta[property='og:title']");return r?r.getAttribute("content"):t.querySelector("h1")}extractAuthor(t){let e=t.querySelector(".booknav2 p a[href*='/author/']");if(e)return e.textContent.trim();let r=t.querySelector("meta[property='og:novel:author']");return r?r.getAttribute("content"):super.extractAuthor(t)}extractLanguage(){return"zh"}extractSubject(t){let e=t.querySelector("meta[property='og:novel:category']");if(e)return e.getAttribute("content");let r=t.querySelector(".booknav2 p a[href*='/class/']");return r?.textContent?.trim()??""}extractDescription(t){let e=t.querySelector("meta[property='og:description']");if(e)return e.getAttribute("content");let r=t.querySelector(".navtxt p");return r?.textContent?.trim()??""}findChapterTitle(t){return t.querySelector(".txtnav h1, #container .txtnav h1, h1")}findCoverImageUrl(t){let e=t.querySelector("meta[property='og:image']");if(e)return e.getAttribute("content");let r=t.querySelector(".bookimg2 img, .bookimg img");if(r)return r.src;let o=this.extractBookId(t.baseURI);return o?`https://twkan.com/files/article/image/${o.substring(0,2)}/${o}/${o}s.jpg`:null}extractBookId(t){let e=t.match(/\/(?:book|txt)\/(\d+)/);return e?e[1]:null}removeUnwantedElementsFromContentElement(t){util.removeChildElementsMatchingSelector(t,"script, .ads, .ad, .advertisement, #ad, .social-share, .share-buttons, .txtcenter, .adsbygoogle, ins.adsbygoogle"),super.removeUnwantedElementsFromContentElement(t)}}